    if (gallery) {
        const items = gallery.querySelectorAll('.gallery-item');

        items.forEach((item, index) => {
            item.addEventListener('click', () => {
                const url = links2[index];
                if (url && url !== '#') {
                    window.open(url, '_blank');
                }
            });
        });
    }
});
